{
  "root_cause_assessment": {
    "most_likely_root_cause": "configured_webhook_url points to initial intake route instead of final return handler",
    "confidence": "high",
    "why": [
      "initial handler only validates document.uploaded and never touches compliLinkWebhookEvents",
      "final handler (handleCompliLinkReturnWebhook) is the only code path that inserts events",
      "dispatches succeed (202 + correlationId) but events table stays empty"
    ]
  },
  "recommended_fix": {
    "change_type": "config_only",
    "target_url": "https://auditapatron.com/api/integrations/auditapatron/bridge",
    "need_backward_compatibility": true,
    "why": [
      "alias already exists and routes to final handler",
      "only env var change required, no code or route modifications",
      "preserves existing dispatch flow"
    ]
  },
  "validation_plan": {
    "checks": [
      "trigger controlled dispatch after config update",
      "verify correlationId reaches final handler",
      "confirm compliLinkWebhookEvents row is inserted"
    ],
    "expected_success_signal": [
      "webhookEvents populated with final event",
      "document updated and case event added"
    ],
    "rollback_condition": [
      "no events inserted after 2 test runs",
      "HTTP 4xx/5xx on bridge alias"
    ]
  },
  "risks": [
    "external service must accept new callback URL",
    "brief dual-URL window if old config cached"
  ],
  "one_sentence_verdict": "Change the env-managed webhook URL to the existing bridge alias to route callbacks to the final handler with zero code changes."
}

